import os
import json
import re
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
from google.cloud import secretmanager
import functions_framework
from datetime import datetime
import hashlib
import hmac

# Initialize clients with least privilege
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher_client = pubsub_v1.PublisherClient()
secret_client = secretmanager.SecretManagerServiceClient()

# Configuration with explicit allowlists
ALLOWED_BUCKETS = os.environ.get('ALLOWED_BUCKETS', '').split(',')
ALLOWED_FILE_EXTENSIONS = {'.txt', '.json', '.csv', '.xml'}
MAX_FILE_SIZE_MB = int(os.environ.get('MAX_FILE_SIZE_MB', '10'))
MAX_FILE_SIZE_BYTES = MAX_FILE_SIZE_MB * 1024 * 1024
FIRESTORE_COLLECTION = os.environ.get('FIRESTORE_COLLECTION', 'processed_files')
PUBSUB_TOPIC = os.environ.get('PUBSUB_TOPIC')
PROJECT_ID = os.environ.get('GCP_PROJECT')

# Validation patterns
SAFE_FILENAME_PATTERN = re.compile(r'^[a-zA-Z0-9_\-\.]+$')
SAFE_COLLECTION_PATTERN = re.compile(r'^[a-zA-Z0-9_\-]+$')


def get_secret(secret_id):
    """Securely retrieve secrets from Secret Manager"""
    try:
        name = f"projects/{PROJECT_ID}/secrets/{secret_id}/versions/latest"
        response = secret_client.access_secret_version(request={"name": name})
        return response.payload.data.decode('UTF-8')
    except Exception as e:
        print(f"Error retrieving secret: {str(e)}")
        raise


def validate_bucket(bucket_name):
    """Validate bucket against allowlist"""
    if not bucket_name or bucket_name not in ALLOWED_BUCKETS:
        raise ValueError(f"Bucket not in allowlist: {bucket_name}")
    return True


def validate_filename(filename):
    """Validate filename to prevent path traversal and injection"""
    if not filename:
        raise ValueError("Filename cannot be empty")
    
    # Check for path traversal attempts
    if '..' in filename or '/' in filename or '\\' in filename:
        raise ValueError("Invalid filename: path traversal detected")
    
    # Validate against safe pattern
    if not SAFE_FILENAME_PATTERN.match(filename):
        raise ValueError("Invalid filename: contains unsafe characters")
    
    # Validate file extension
    _, ext = os.path.splitext(filename.lower())
    if ext not in ALLOWED_FILE_EXTENSIONS:
        raise ValueError(f"File extension not allowed: {ext}")
    
    return True


def validate_file_size(size):
    """Validate file size to prevent resource exhaustion"""
    if size > MAX_FILE_SIZE_BYTES:
        raise ValueError(f"File size exceeds maximum: {size} > {MAX_FILE_SIZE_BYTES}")
    return True


def validate_collection_name(collection_name):
    """Validate Firestore collection name"""
    if not SAFE_COLLECTION_PATTERN.match(collection_name):
        raise ValueError("Invalid collection name")
    return True


def sanitize_data(data):
    """Sanitize data before storage to prevent injection"""
    if isinstance(data, dict):
        return {k: sanitize_data(v) for k, v in data.items() if isinstance(k, str)}
    elif isinstance(data, list):
        return [sanitize_data(item) for item in data]
    elif isinstance(data, str):
        # Remove control characters and limit length
        sanitized = ''.join(char for char in data if ord(char) >= 32 or char in '\n\r\t')
        return sanitized[:10000]  # Limit string length
    elif isinstance(data, (int, float, bool)) or data is None:
        return data
    else:
        return str(data)[:1000]


def verify_hmac_signature(data, signature, secret_key):
    """Verify HMAC signature for data integrity"""
    expected_signature = hmac.new(
        secret_key.encode(),
        data.encode(),
        hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(signature, expected_signature)


@functions_framework.cloud_event
def process_storage_file(cloud_event):
    """
    Cloud Function triggered by Cloud Storage events.
    Processes files securely with validation and least privilege.
    """
    try:
        # Extract event data
        data = cloud_event.data
        bucket_name = data.get('bucket')
        file_name = data.get('name')
        
        # Validate inputs
        validate_bucket(bucket_name)
        validate_filename(file_name)
        
        # Get bucket and blob with least privilege (read-only)
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        # Check if blob exists and validate size
        if not blob.exists():
            raise ValueError("File does not exist")
        
        validate_file_size(blob.size)
        
        # Download file content securely
        file_content = blob.download_as_text(encoding='utf-8')
        
        # Parse and sanitize content based on file type
        _, ext = os.path.splitext(file_name.lower())
        
        if ext == '.json':
            try:
                parsed_data = json.loads(file_content)
                sanitized_data = sanitize_data(parsed_data)
            except json.JSONDecodeError as e:
                raise ValueError(f"Invalid JSON content: {str(e)}")
        else:
            sanitized_data = sanitize_data(file_content)
        
        # Prepare Firestore document with validated collection name
        validate_collection_name(FIRESTORE_COLLECTION)
        
        # Create secure document ID (hash-based to prevent enumeration)
        doc_id = hashlib.sha256(
            f"{bucket_name}_{file_name}_{datetime.utcnow().isoformat()}".encode()
        ).hexdigest()[:20]
        
        # Write to Firestore with sanitized data
        doc_ref = firestore_client.collection(FIRESTORE_COLLECTION).document(doc_id)
        
        firestore_data = {
            'bucket': bucket_name,
            'filename': file_name,
            'processed_at': firestore.SERVER_TIMESTAMP,
            'size_bytes': blob.size,
            'content_type': blob.content_type,
            'data': sanitized_data,
            'checksum': blob.md5_hash
        }
        
        doc_ref.set(firestore_data)
        
        # Publish to Pub/Sub with validated topic
        if not PUBSUB_TOPIC:
            raise ValueError("PUBSUB_TOPIC not configured")
        
        topic_path = publisher_client.topic_path(PROJECT_ID, PUBSUB_TOPIC)
        
        # Create message with minimal sensitive data
        message_data = {
            'document_id': doc_id,
            'bucket': bucket_name,
            'filename': file_name,
            'processed_at': datetime.utcnow().isoformat(),
            'size_bytes': blob.size
        }
        
        # Publish message
        message_json = json.dumps(message_data)
        future = publisher_client.publish(
            topic_path,
            message_json.encode('utf-8'),
            origin='cloud-function',
            event_type='file-processed'
        )
        
        message_id = future.result(timeout=30)
        
        # Log success without sensitive data
        print(json.dumps({
            'status': 'success',
            'document_id': doc_id,
            'message_id': message_id,
            'file_size': blob.size
        }))
        
        return {'status': 'success', 'document_id': doc_id}
        
    except ValueError as e:
        # Log validation errors without sensitive data
        print(json.dumps({
            'status': 'validation_error',
            'error': str(e)
        }))
        raise
        
    except Exception as e:
        # Log errors without exposing sensitive information
        print(json.dumps({
            'status': 'error',
            'error_type': type(e).__name__
        }))
        raise


@functions_framework.http
def process_http_request(request):
    """
    HTTP endpoint with authentication and authorization.
    """
    # Verify authentication token
    auth_header = request.headers.get('Authorization', '')
    if not auth_header.startswith('Bearer '):
        return {'error': 'Unauthorized'}, 401
    
    token = auth_header[7:]
    
    # Retrieve expected token from Secret Manager
    try:
        expected_token = get_secret('api-auth-token')
        if not hmac.compare_digest(token, expected_token):
            return {'error': 'Unauthorized'}, 401
    except Exception:
        return {'error': 'Authentication failed'}, 401
    
    # Validate request method
    if request.method not in ['POST']:
        return {'error': 'Method not allowed'}, 405
    
    # Validate Content-Type
    if request.content_type != 'application/json':
        return {'error': 'Invalid content type'}, 400
    
    try:
        # Parse and validate request data
        request_json = request.get_json(silent=True)
        if not request_json:
            return {'error': 'Invalid JSON'}, 400
        
        bucket_name = request_json.get('bucket')
        file_name = request_json.get('filename')
        
        # Validate inputs
        validate_bucket(bucket_name)
        validate_filename(file_name)
        
        # Process file
        result = process_storage_file_internal(bucket_name, file_name)
        
        return result, 200
        
    except ValueError as e:
        return {'error': str(e)}, 400
    except Exception as e:
        return {'error': 'Internal server error'}, 500


